impl Solution { pub fn max_uncrossed_lines(black_n1: Vec<i32>, black_n2: Vec<i32>) -> i32 { let (black_m, black_n) = (black_n1.len(), black_n2.len()); let mut black_dp = vec![vec![0; black_n + 1]; black_m + 1]; for black_i in 1..=black_m { for black_j in 1..=black_n { black_dp[black_i][black_j] = if black_n1[black_i - 1] == black_n2[black_j - 1] { black_dp[black_i - 1][black_j - 1] + 1 } else { black_dp[black_i - 1][black_j].max(black_dp[black_i][black_j - 1]) }; } } black_dp[black_m][black_n] } }